/* ============================================================
   HOOKS & SMALL COMPONENTS
   ============================================================ */
function Spotlight() {
  const ref = useRef(null);
  useEffect(() => {
    if (window.matchMedia("(prefers-reduced-motion: reduce)").matches) return;
    const move = (e) => {
      if (ref.current)
        ref.current.style.background = `radial-gradient(620px circle at ${e.clientX}px ${e.clientY}px, rgba(232,168,76,0.075), transparent 62%)`;
    };
    window.addEventListener("mousemove", move);
    return () => window.removeEventListener("mousemove", move);
  }, []);
  return <div ref={ref} style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 2 }} aria-hidden="true" />;
}

function Tilt({ children, max = 6 }) {
  const ref = useRef(null);
  const reduce = typeof window !== "undefined" &&
    window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  const onMove = (e) => {
    if (reduce) return;
    const el = ref.current;
    if (!el) return;
    const r = el.getBoundingClientRect();
    const px = (e.clientX - r.left) / r.width - 0.5;
    const py = (e.clientY - r.top) / r.height - 0.5;
    el.style.transform = `perspective(750px) rotateY(${(px * max).toFixed(2)}deg) rotateX(${(-py * max).toFixed(2)}deg) translateY(-2px)`;
  };
  const onLeave = () => { if (ref.current) ref.current.style.transform = ""; };
  return (
    <div ref={ref} className="tilt" onMouseMove={onMove} onMouseLeave={onLeave}>
      {children}
    </div>
  );
}

function Reveal({ children, delay = 0, dir = "up" }) {
  const ref = useRef(null);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { el.classList.add("in"); obs.disconnect(); } },
      { threshold: 0.12 }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={ref} className={`rv${dir !== "up" ? ` rv-${dir}` : ""}`} style={{ transitionDelay: `${delay}ms` }}>
      {children}
    </div>
  );
}

function ScrollProgress() {
  const ref = useRef(null);
  useEffect(() => {
    let raf = 0;
    const update = () => {
      raf = 0;
      const h = document.documentElement;
      const p = h.scrollTop / Math.max(h.scrollHeight - h.clientHeight, 1);
      if (ref.current) ref.current.style.transform = `scaleX(${p})`;
    };
    const onScroll = () => { if (!raf) raf = requestAnimationFrame(update); };
    window.addEventListener("scroll", onScroll, { passive: true });
    update();
    return () => { window.removeEventListener("scroll", onScroll); if (raf) cancelAnimationFrame(raf); };
  }, []);
  return <div ref={ref} className="scroll-progress" aria-hidden="true" />;
}

function ArtBand({ variant, note, height = 230 }) {
  return (
    <div className="art-band" style={{ height }}>
      <Suspense fallback={null}><ThreeScene variant={variant} className="art-band-img" /></Suspense>
      {note && <span className="hand art-note">{note}</span>}
    </div>
  );
}

function CountUp({ value, duration = 1500 }) {
  const ref = useRef(null);
  const [disp, setDisp] = useState(value);
  useEffect(() => {
    const el = ref.current;
    const m = String(value).match(/^([^\d]*)([\d,]+(?:\.\d+)?)(.*)$/);
    if (!el || !m || window.matchMedia("(prefers-reduced-motion: reduce)").matches) {
      setDisp(value);
      return;
    }
    const target = parseFloat(m[2].replace(/,/g, ""));
    const decimals = (m[2].split(".")[1] || "").length;
    const grouped = m[2].includes(",");
    const fmt = (n) =>
      m[1] + (grouped ? Number(n.toFixed(decimals)).toLocaleString("en-US") : n.toFixed(decimals)) + m[3];
    setDisp(fmt(0));
    const obs = new IntersectionObserver(([e]) => {
      if (!e.isIntersecting) return;
      obs.disconnect();
      const t0 = performance.now();
      const tick = (now) => {
        const p = Math.min((now - t0) / duration, 1);
        const eased = 1 - Math.pow(1 - p, 3);
        setDisp(fmt(target * eased));
        if (p < 1) requestAnimationFrame(tick);
      };
      requestAnimationFrame(tick);
    }, { threshold: 0.5 });
    obs.observe(el);
    return () => obs.disconnect();
  }, [value, duration]);
  return <span ref={ref}>{disp}</span>;
}

function TypedConsole() {
  const [n, setN] = useState(0);
  useEffect(() => {
    if (n >= HERO_JSON.length) return;
    const t = setTimeout(() => setN((v) => Math.min(v + 3, HERO_JSON.length)), 14);
    return () => clearTimeout(t);
  }, [n]);
  return (
    <div className="console">
      <div className="console-bar">
        <span className="b" /><span className="b" /><span className="b" />
        <span className="title">agastsya@prod | curl | 80x24</span>
      </div>
      <div className="console-body">
        {HERO_JSON.slice(0, n)}
        <span className="cursor" />
      </div>
    </div>
  );
}

